import { useEffect, useRef, useState, type FormEvent } from 'react'
import { useNavigate } from 'react-router-dom'
import { motion, AnimatePresence } from 'framer-motion'
import { supabase } from '@/lib/supabase'
import { useAuthStore } from '@/store/useAuthStore'
import { useFilterStore } from '@/store/useFilterStore'
import { loadFilteredVocab, pickRandom, type VocabCard } from '@/lib/vocab'
import { levenshtein, normalizeForCompare } from '@/lib/levenshtein'
import { awardXp } from '@/lib/xp'
import { fireFlowerConfetti } from '@/lib/confetti'
import { Header } from '@/components/Header'
import { DiacriticKeyboard } from '@/components/DiacriticKeyboard'
import { XPToast, type XpToastData } from '@/components/XPToast'

// Modus 6 — Aktiver Vokabeltrainer (Tippen) laut CLAUDE.md §6.6.
//
// Direction-Toggle:
//   DE→HU (default, härter): User sieht german, tippt hungarian
//   HU→DE: User sieht hungarian, tippt german
//
// Auswertung (Levenshtein-Distanz nach normalizeForCompare):
//   0 chars: exakt        → +15 XP, production_streak +1
//   1 char abweichung:    → +8 XP,  production_streak reset
//   2 chars:              → +3 XP,  production_streak reset
//   >2:                   → -2 XP,  production_streak reset
//
// Production-Mastery: 5× exakt in Folge → srs_medical.production_mastered_at
// setzen + +50 XP Bonus + 🏆-Badge.

type Direction = 'de_to_hu' | 'hu_to_de'

type Verdict = {
  status: 'exact' | 'one_off' | 'two_off' | 'fail'
  distance: number
  baseXp: number
  expected: string
  actual: string
}

const ROUND_SIZE = 10

export default function VocabTrainer() {
  const { user } = useAuthStore()
  const filter = useFilterStore()
  const navigate = useNavigate()

  const [direction, setDirection] = useState<Direction>('de_to_hu')
  const [pool, setPool] = useState<VocabCard[] | null>(null)
  const [round, setRound] = useState<VocabCard[]>([])
  const [step, setStep] = useState(0)
  const [input, setInput] = useState('')
  const [verdict, setVerdict] = useState<Verdict | null>(null)
  const [stats, setStats] = useState({ exact: 0, oneOff: 0, twoOff: 0, fail: 0, totalXp: 0, masteredCards: [] as string[] })
  const [done, setDone] = useState(false)
  const [toast, setToast] = useState<XpToastData | null>(null)
  const [error, setError] = useState<string | null>(null)
  const inputRef = useRef<HTMLInputElement | null>(null)

  // Pool + SRS-Map laden
  useEffect(() => {
    if (!user) return
    let cancelled = false
    async function load() {
      try {
        const cards = await loadFilteredVocab(filter, user!.id)
        if (cancelled) return
        if (cards.length < ROUND_SIZE) {
          setError(`Zu wenige Karten gefunden (${cards.length}). Andere Filter probieren.`)
          return
        }
        setPool(cards)
        startRound(cards)
      } catch (e) {
        setError(String((e as Error).message ?? e))
      }
    }
    void load()
    return () => { cancelled = true }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user, filter.category, filter.wordClass, filter.difficulty, filter.mastery])

  function startRound(fromPool?: VocabCard[]) {
    const p = fromPool ?? pool
    if (!p) return
    const r = pickRandom(p, ROUND_SIZE)
    setRound(r)
    setStep(0)
    setInput('')
    setVerdict(null)
    setStats({ exact: 0, oneOff: 0, twoOff: 0, fail: 0, totalXp: 0, masteredCards: [] })
    setDone(false)
    requestAnimationFrame(() => inputRef.current?.focus())
  }

  const current = round[step] ?? null
  const prompt = current ? (direction === 'de_to_hu' ? current.german : current.hungarian) : ''
  const expectedAnswer = current ? (direction === 'de_to_hu' ? current.hungarian : current.german) : ''
  const inputLang = direction === 'de_to_hu' ? 'hu' : 'de'

  async function handleSubmit(e?: FormEvent) {
    e?.preventDefault()
    if (!current || verdict || !input.trim() || !user) return

    const normUser = normalizeForCompare(input)
    const normExpected = normalizeForCompare(expectedAnswer)
    const dist = levenshtein(normUser, normExpected)

    let v: Verdict
    if (dist === 0) {
      v = { status: 'exact', distance: 0, baseXp: 15, expected: expectedAnswer, actual: input }
    } else if (dist === 1) {
      v = { status: 'one_off', distance: 1, baseXp: 8, expected: expectedAnswer, actual: input }
    } else if (dist === 2) {
      v = { status: 'two_off', distance: 2, baseXp: 3, expected: expectedAnswer, actual: input }
    } else {
      v = { status: 'fail', distance: dist, baseXp: -2, expected: expectedAnswer, actual: input }
    }
    setVerdict(v)

    if (v.status === 'exact') fireFlowerConfetti()

    // XP-Vergabe (kann negativ sein)
    void awardXp({
      baseAmount: v.baseXp,
      source: `vocab_trainer_${v.status}`,
      mode: 'medical'
    }).then((r) => r && setToast({ id: Date.now(), ...r }))

    // Production-Mastery: nur bei DE→HU (active recall), und nur wenn exakt.
    // Dabei production_streak inkrementieren / resetten.
    void persistProductionMastery(user.id, current, v.status === 'exact', direction)
      .then((res) => {
        if (res?.justMastered) {
          setStats((s) => ({ ...s, masteredCards: [...s.masteredCards, current.hungarian] }))
          // +50 XP Mastery-Bonus on top
          void awardXp({ baseAmount: 50, source: 'production_mastered', mode: 'medical' })
        }
      })

    // Stats updaten
    setStats((s) => {
      const next = { ...s }
      if (v.status === 'exact') next.exact += 1
      else if (v.status === 'one_off') next.oneOff += 1
      else if (v.status === 'two_off') next.twoOff += 1
      else next.fail += 1
      next.totalXp += v.baseXp
      return next
    })
  }

  function handleNext() {
    if (step + 1 >= round.length) {
      setDone(true)
      return
    }
    setStep((s) => s + 1)
    setInput('')
    setVerdict(null)
    requestAnimationFrame(() => inputRef.current?.focus())
  }

  useEffect(() => {
    if (!toast) return
    const t = setTimeout(() => setToast(null), 1200)
    return () => clearTimeout(t)
  }, [toast])

  // Direction-Toggle: round neu mischen wenn umgeschaltet
  function flipDirection() {
    setDirection((d) => (d === 'de_to_hu' ? 'hu_to_de' : 'de_to_hu'))
    if (pool) startRound(pool)
  }

  if (error) return <Wrapper><Status>⚠ {error}</Status><button onClick={() => navigate('/home')} style={btnGhost}>Zurück</button></Wrapper>
  if (!pool || !current) return <Wrapper><Status>Karten werden geladen…</Status></Wrapper>

  if (done) {
    return (
      <DoneScreen
        stats={stats}
        onRestart={() => startRound()}
        onHome={() => navigate('/home')}
      />
    )
  }

  return (
    <Wrapper>
      {/* Top: Direction + Progress */}
      <div
        style={{
          width: '100%',
          maxWidth: 480,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: '0.6rem',
          gap: 8
        }}
      >
        <button
          onClick={flipDirection}
          disabled={!!verdict}
          style={{
            background: 'var(--white)',
            border: '1.5px solid var(--green)',
            color: 'var(--green)',
            padding: '0.4rem 0.7rem',
            borderRadius: 8,
            fontFamily: 'inherit',
            fontWeight: 600,
            fontSize: '0.8rem',
            cursor: verdict ? 'default' : 'pointer',
            opacity: verdict ? 0.5 : 1
          }}
          aria-label="Richtung wechseln"
        >
          {direction === 'de_to_hu' ? '🇩🇪 → 🇭🇺' : '🇭🇺 → 🇩🇪'}
        </button>
        <div style={{ fontSize: '0.85rem', opacity: 0.65 }}>
          {step + 1} / {round.length}
        </div>
      </div>

      {/* Source-Card */}
      <div
        style={{
          width: '100%',
          maxWidth: 480,
          background: 'var(--white)',
          border: '2px solid var(--red)',
          borderRadius: 14,
          padding: '1.5rem 1rem',
          textAlign: 'center',
          boxShadow: 'var(--shadow-card)'
        }}
      >
        <div style={{ fontSize: '0.7rem', opacity: 0.55, letterSpacing: '0.5px', marginBottom: 6 }}>
          {direction === 'de_to_hu' ? 'DEUTSCH' : 'UNGARISCH'}
        </div>
        <div className={direction === 'hu_to_de' ? 'hu-vocab' : ''} style={{ color: 'var(--red)', fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: direction === 'hu_to_de' ? '2rem' : '1.6rem' }}>
          {prompt}
        </div>
        {direction === 'hu_to_de' && current.phonetic && (
          <div className="phonetic" style={{ marginTop: 4, fontSize: '0.85rem' }}>[{current.phonetic}]</div>
        )}
      </div>

      {/* Eingabe */}
      <form onSubmit={handleSubmit} style={{ width: '100%', maxWidth: 480, marginTop: '1rem', display: 'flex', flexDirection: 'column', gap: 10 }}>
        <input
          ref={inputRef}
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          disabled={!!verdict}
          autoComplete="off"
          autoCorrect="off"
          autoCapitalize="off"
          spellCheck={false}
          placeholder={direction === 'de_to_hu' ? 'Auf Ungarisch tippen…' : 'Auf Deutsch tippen…'}
          style={{
            padding: '0.85rem 1rem',
            fontSize: '1.15rem',
            border: `2px solid ${verdictBorderColor(verdict)}`,
            borderRadius: 12,
            fontFamily: 'Georgia, serif',
            fontWeight: 600,
            background: 'var(--white)',
            outline: 'none',
            transition: 'border-color 200ms'
          }}
        />

        <DiacriticKeyboard lang={inputLang} inputRef={inputRef} onChange={setInput} />

        {!verdict ? (
          <button
            type="submit"
            disabled={!input.trim()}
            style={{
              background: 'var(--red)',
              color: 'var(--cream)',
              border: 'none',
              padding: '0.8rem',
              borderRadius: 10,
              fontWeight: 700,
              fontSize: '1rem',
              fontFamily: 'inherit',
              cursor: !input.trim() ? 'default' : 'pointer',
              opacity: !input.trim() ? 0.5 : 1,
              marginTop: 4
            }}
          >
            Prüfen
          </button>
        ) : (
          <VerdictPanel verdict={verdict} onNext={handleNext} isLast={step + 1 >= round.length} />
        )}
      </form>

      <button onClick={() => navigate('/home')} style={{ ...btnGhost, marginTop: '1.5rem' }}>
        Sitzung abbrechen
      </button>

      <XPToast toast={toast} />
    </Wrapper>
  )
}

function VerdictPanel({ verdict, onNext, isLast }: { verdict: Verdict; onNext: () => void; isLast: boolean }) {
  const config = {
    exact:    { emoji: '✅', label: 'Exakt!',          color: 'var(--green)',  desc: 'Perfekt geschrieben.' },
    one_off:  { emoji: '⚠️', label: 'Fast',            color: 'var(--orange)', desc: '1 Zeichen daneben.' },
    two_off:  { emoji: '⚠️', label: 'Knapp daneben',   color: 'var(--orange)', desc: '2 Zeichen daneben.' },
    fail:     { emoji: '❌', label: 'Daneben',         color: 'var(--red)',    desc: `${verdict.distance} Zeichen daneben.` }
  }[verdict.status]

  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      style={{
        background: 'var(--white)',
        border: `2px solid ${config.color}`,
        borderRadius: 12,
        padding: '0.9rem 1rem',
        marginTop: 4,
        textAlign: 'center'
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, marginBottom: 6 }}>
        <span style={{ fontSize: '1.5rem' }}>{config.emoji}</span>
        <span style={{ fontFamily: 'Georgia, serif', fontWeight: 700, color: config.color, fontSize: '1.05rem' }}>
          {config.label}
        </span>
      </div>
      <div style={{ fontSize: '0.85rem', opacity: 0.75, marginBottom: 4 }}>{config.desc}</div>
      {verdict.status !== 'exact' && (
        <div style={{ marginTop: '0.5rem', fontSize: '0.9rem' }}>
          <span style={{ opacity: 0.6 }}>Korrekt: </span>
          <b style={{ fontFamily: 'Georgia, serif', color: 'var(--green)' }}>{verdict.expected}</b>
        </div>
      )}
      <button
        onClick={onNext}
        autoFocus
        style={{
          marginTop: '0.85rem',
          background: config.color,
          color: 'var(--cream)',
          border: 'none',
          padding: '0.6rem 1.4rem',
          borderRadius: 8,
          fontWeight: 700,
          fontSize: '0.95rem',
          fontFamily: 'inherit',
          cursor: 'pointer'
        }}
      >
        {isLast ? 'Ergebnis' : 'Weiter'}
      </button>
    </motion.div>
  )
}

function DoneScreen({
  stats,
  onRestart,
  onHome
}: {
  stats: { exact: number; oneOff: number; twoOff: number; fail: number; totalXp: number; masteredCards: string[] }
  onRestart: () => void
  onHome: () => void
}) {
  return (
    <Wrapper>
      <div style={{ textAlign: 'center', maxWidth: 420, width: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 12 }}>
        <div style={{ fontSize: '4rem' }}>{stats.masteredCards.length > 0 ? '🏆' : '🌺'}</div>
        <h1 className="app-name" style={{ color: 'var(--green)', fontSize: '1.8rem', margin: 0 }}>
          Runde fertig
        </h1>

        <div
          style={{
            background: 'var(--white)',
            border: '2px solid var(--green)',
            borderRadius: 14,
            padding: '1.2rem',
            boxShadow: 'var(--shadow-card)',
            width: '100%',
            display: 'flex',
            flexDirection: 'column',
            gap: '0.6rem'
          }}
        >
          <Row label="✅ Exakt (×15)"   value={stats.exact} highlight />
          <Row label="⚠️ 1 Zchn (×8)"   value={stats.oneOff} />
          <Row label="⚠️ 2 Zchn (×3)"   value={stats.twoOff} />
          <Row label="❌ Daneben (×−2)" value={stats.fail} />
          <div style={{ height: 1, background: 'rgba(0,0,0,0.08)', margin: '0.3rem 0' }} />
          <div style={{ display: 'flex', justifyContent: 'space-between', fontFamily: 'Georgia, serif', fontWeight: 700, color: 'var(--red)', fontSize: '1.2rem' }}>
            <span>Insgesamt</span>
            <span>{stats.totalXp >= 0 ? '+' : ''}{stats.totalXp} XP</span>
          </div>
        </div>

        <AnimatePresence>
          {stats.masteredCards.length > 0 && (
            <motion.div
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              style={{
                background: 'var(--green)',
                color: 'var(--cream)',
                padding: '0.7rem 1rem',
                borderRadius: 12,
                width: '100%',
                fontSize: '0.9rem'
              }}
            >
              <div style={{ fontWeight: 700, marginBottom: 4 }}>🏆 Production-Mastered</div>
              {stats.masteredCards.map((w) => <div key={w} style={{ fontFamily: 'Georgia, serif' }}>{w}</div>)}
              <div style={{ fontSize: '0.75rem', opacity: 0.85, marginTop: 4 }}>+50 XP pro Wort (zusätzlich)</div>
            </motion.div>
          )}
        </AnimatePresence>

        <div style={{ display: 'flex', flexDirection: 'column', gap: 8, width: '100%', marginTop: '0.5rem' }}>
          <button onClick={onRestart} style={{ background: 'var(--red)', color: 'var(--cream)', border: 'none', padding: '0.8rem', borderRadius: 10, fontWeight: 700, fontSize: '1rem', fontFamily: 'inherit', cursor: 'pointer' }}>
            Nochmal
          </button>
          <button onClick={onHome} style={{ background: 'none', border: '2px solid var(--red)', color: 'var(--red)', padding: '0.7rem', borderRadius: 10, fontWeight: 600, fontSize: '0.95rem', fontFamily: 'inherit', cursor: 'pointer' }}>
            Zurück zu Home
          </button>
        </div>
      </div>
    </Wrapper>
  )
}

function Row({ label, value, highlight }: { label: string; value: number; highlight?: boolean }) {
  return (
    <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.95rem', fontWeight: highlight ? 700 : 500, color: highlight ? 'var(--red)' : 'inherit' }}>
      <span style={{ opacity: 0.75 }}>{label}</span>
      <span>{value}</span>
    </div>
  )
}

/**
 * Production-Mastery: streak counter im srs_medical.
 *
 * - Bei exakt + DE→HU (active recall): production_streak += 1.
 *   Erreicht 5 → production_mastered_at = now() (idempotent: nur wenn null).
 * - Bei nicht-exakt: production_streak = 0.
 * - HU→DE wird ignoriert (passive recognition, zählt nicht für Mastery).
 * Returnt { justMastered: boolean } — true wenn dieser Hit den Threshold knackte.
 */
async function persistProductionMastery(
  userId: string,
  card: VocabCard,
  isExact: boolean,
  direction: Direction
): Promise<{ justMastered: boolean } | null> {
  if (direction !== 'de_to_hu') return null

  const { data: existing } = await supabase
    .from('srs_medical')
    .select('id, production_streak, production_mastered_at')
    .eq('user_id', userId)
    .eq('card_id', card.id)
    .maybeSingle()

  type Row = { id: number; production_streak: number; production_mastered_at: string | null } | null
  const row = existing as Row

  if (!isExact) {
    if (row) {
      await supabase
        .from('srs_medical')
        .update({ production_streak: 0 })
        .eq('id', row.id)
    }
    return { justMastered: false }
  }

  // Exakt
  const newStreak = (row?.production_streak ?? 0) + 1
  const reachedMastery = newStreak >= 5 && !row?.production_mastered_at
  const updates: Record<string, unknown> = {
    production_streak: newStreak,
    last_reviewed_at: new Date().toISOString()
  }
  if (reachedMastery) updates.production_mastered_at = new Date().toISOString()

  if (row) {
    await supabase.from('srs_medical').update(updates).eq('id', row.id)
  } else {
    // Keine SRS-Row → neue erstellen mit allen relevanten Defaults
    await supabase.from('srs_medical').insert({
      user_id: userId,
      card_id: card.id,
      production_streak: newStreak,
      production_mastered_at: reachedMastery ? new Date().toISOString() : null,
      last_reviewed_at: new Date().toISOString()
    })
  }

  return { justMastered: reachedMastery }
}

function verdictBorderColor(v: Verdict | null): string {
  if (!v) return 'rgba(0,0,0,0.15)'
  if (v.status === 'exact') return 'var(--green)'
  if (v.status === 'fail') return 'var(--red)'
  return 'var(--orange)'
}

function Wrapper({ children }: { children: React.ReactNode }) {
  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}>
      <Header />
      <main style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '1.5rem 1rem 3rem' }}>
        {children}
      </main>
    </div>
  )
}

function Status({ children }: { children: React.ReactNode }) {
  return <div style={{ opacity: 0.55, fontSize: '0.95rem', marginTop: '20vh' }}>{children}</div>
}

const btnGhost: React.CSSProperties = {
  background: 'none',
  border: '1.5px solid rgba(0,0,0,0.15)',
  padding: '0.45rem 0.9rem',
  borderRadius: 8,
  fontFamily: 'inherit',
  fontSize: '0.8rem',
  cursor: 'pointer',
  opacity: 0.65
}
